"""
mkt-original | Numbers 25-26 | Baal Peor + second census
Run: python3 scripts/zc-original-numbers-25-26.py

Ch 25 (18 verses): The apostasy at Shittim — Israel yokes itself (ṣemed) to Baal
Peor; Phinehas' act of zealous atonement. Key terms: wayyiṣamed (25:3, to yoke
oneself to a foreign god), qinˀat YHWH (Phinehas' divine zeal, 25:11), brit shalom
(covenant of peace, 25:12), brit kehunnat ˁolam (everlasting priesthood, 25:13).

Ch 26 (65 verses): The second census — a whole generation after the first (Num 1).
Every man counted in the first census is now dead except Caleb and Joshua (26:64-65).
Key: clan names and etymologies, the Simeon collapse (22,200, down from 59,300),
the Korah exception (sons of Korah survived, 26:11), Judah's Pharez/Perez line
(messianic genealogy, 26:20-21), the land-by-lot system (26:55-56), and the
two survivors formula (26:65) that closes the forty-year death march.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}


def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


NUMBERS = {
    "25": {
        "1": "<p><span class='term'>wayyaḥel haˁam liznot</span> (וַיָּחֶל הָעָם לִזְנוֹת) — 'the people began to commit fornication.' <em>Ḥalal</em> in hiphil = to begin, but also to profane/defile. The form carries both: to begin is to defile. <em>Liznot</em> (from <em>zanah</em> = to fornicate, play the harlot) is the vocabulary of spiritual and physical unfaithfulness throughout the prophets (Ezek 16, 23; Hos 1-3). Shittim (שִׁטִּים, acacia trees) — Israel's final campsite before Canaan; the first failure happens at the threshold of the promise.</p>",
        "2": "<p><span class='term'>wayyiqreˀu laˁam leziḇḥey ˀeloheyhen</span> — the Moabite women invited Israel to the sacrifices of their gods. Cultic meals bind worshippers to the deity they honor: eating at a god's table creates allegiance. Paul uses this principle in 1 Cor 10:18-21: those who eat at the table of demons share with demons. The Baal Peor meal is the anti-type of the Lord's Supper — communion with what is not God.</p>",
        "3": "<p><span class='term'>wayyiṣamed Yisraˀel levaˁal Peˁor</span> (וַיִּצָּמֶד יִשְׂרָאֵל לְבַעַל פְּעוֹר) — Israel yoked itself to Baal Peor. <em>Ṣamed</em> = to yoke, attach (as animals in a team). The metaphor is deliberate: Israel entered a working partnership with a foreign god — a yoking that is the opposite of the exclusive covenant. Paul cites this incident directly: 'We must not indulge in sexual immorality as some of them did, and twenty-three thousand fell in a single day' (1 Cor 10:8).</p>",
        "4": "<p><span class='term'>hôqaˁ ˀotam lYHWH</span> (הוֹקַע אוֹתָם לַיהוָה) — 'hang/expose them to the LORD.' <em>Yaqaˁ</em> = to expose, impale, dislocate; a public execution that removes the curse from the community. The public hanging before YHWH in the sun is covenantal procedure: the community dissociates itself from the guilty. <em>Liyhwh</em> — the execution is done before/for YHWH, not merely as punishment but as religious repair.</p>",
        "5": "<p><span class='term'>ṣimdu levaˁal Peˁor</span> (צְמוּדִים לְבַעַל פְּעוֹר) — yoked to Baal Peor. The hiphil of the previous verse's niphal: the leaders are to put to death those who yoked themselves. The double use of <em>ṣamed</em> reinforces the yoking metaphor: the covenant break is described with agricultural language — they have put on the wrong yoke. Jesus offers his own easy yoke (Matt 11:29-30) in contrast to yoking to false gods.</p>",
        "6": "<p>An Israelite man brings a Midianite woman <span class='term'>leˀeyney Mosheh weleˀeyney kol-ˁedat</span> (לְעֵינֵי מֹשֶׁה וּלְעֵינֵי כָּל-עֲדַת) — before the eyes of Moses and the whole congregation. The brazen public defiance makes the act a theological provocation, not merely a personal sin. The people were weeping at the tent entrance (<em>boke</em> = crying in mourning, perhaps already aware of the plague); the man acts in their sight while they weep.</p>",
        "7": "<p><span class='term'>Pinḥas ben-Elˁazar ben-Aharon hakohen</span> — Phinehas son of Eleazar son of Aaron. The full genealogy establishes priestly credentials: third-generation Aaronide. <span class='term'>wayiqom miqerev haˁedah</span> (וַיָּקָם מִקֶּרֶב הָעֵדָה) — he rose from the midst of the congregation. His is an individual act against communal paralysis; the whole congregation was weeping while one man acted.</p>",
        "8": "<p><span class='term'>wayyidqor ˀet-sheneyhem</span> (וַיִּדְקֹר אֶת-שְׁנֵיהֶם) — 'he pierced/stabbed through both of them.' <em>Daqar</em> = to pierce, run through with a weapon. The same verb appears in Zech 12:10 ('they will look on me, the one they have pierced') — the word for the eschatological mourning over the one who was pierced is the same as Phinehas' act. Through Phinehas the plague stopped (v.8b); through the pierced one the divine wrath is ultimately exhausted.</p>",
        "9": "<p><span class='term'>wayyihyu hammetim bammagepha</span> (וַיִּהְיוּ הַמֵּתִים בַּמַּגֵּפָה) — 'those who died in the plague were twenty-four thousand.' This is the largest single plague death toll in the wilderness narrative. Paul in 1 Cor 10:8 gives the number as twenty-three thousand (in one day) — a near-parallel; the difference may reflect counting conventions (per day vs. total) or a different textual tradition.</p>",
        "10": "<p>YHWH speaks to Moses. The divine speech introduces the theological interpretation of Phinehas' act — his action precedes God's verbal affirmation. In the narrative, physical action stops the plague; God's word follows to explain, reward, and consecrate what zeal accomplished. The sequence matters: zeal acted first; verbal covenant followed.</p>",
        "11": "<p><span class='term'>qinˀ ˀet-qinˀati</span> (קִנֵּא אֶת-קִנְאָתִי) — 'he was zealous with my zeal/jealousy.' A figura etymologica: he was jealous with my jealousy. <em>Qinˀah</em> = jealousy, zeal — both the passionate desire for exclusive allegiance and the burning wrath when that allegiance is violated. YHWH calls Israel's exclusive devotion with the vocabulary of a jealous spouse (Exod 20:5, ˀel qannaˀ = jealous God). Phinehas' zeal is a human participation in divine jealousy — the covenant's passion expressed through a covenant member.</p>",
        "12": "<p><span class='term'>brit shalom</span> (בְּרִית שָׁלוֹם) — covenant of peace. The same phrase used for the eschatological covenant in Isa 54:10 ('my covenant of peace will not be removed') and Ezek 34:25 ('I will make a covenant of peace with them'). Phinehas receives the covenant vocabulary that belongs to the messianic age. His zeal that stopped the plague is a type of the atonement that makes peace — <em>shalom</em> as the result of wrath absorbed.</p>",
        "13": "<p><span class='term'>brit kehunnat ˁolam</span> (בְּרִית כְּהֻנַּת עוֹלָם) — covenant of everlasting priesthood. The Phinehas covenant guarantees his priestly line. <span class='term'>kiper ˁal-bney Yisraˀel</span> (כִּפֶּר עַל-בְּנֵי יִשְׂרָאֵל) — he made atonement for Israel. The atonement vocabulary (<em>kipper</em>, <em>ˁalah</em>) applies to Phinehas' action: his spear-thrust was an act of atonement. This is unusual: kipper typically involves blood rituals at the altar. Here the priestly-zealot's direct action stops divine wrath and accomplishes what the altar rites accomplish.</p>",
        "14": "<p>The Israelite man is identified: <span class='term'>Zimri ben-Salu nˀsiˀ bet-ˀav laShimˁoni</span> — Zimri son of Salu, a leader of Simeon. The Simeonite detail resonates: Simeon as a tribe was severely reduced after Baal Peor (ch 26 records only 22,200 Simeonites vs. 59,300 in the first census). The leader of the tribe that suffered most from the plague is the man who provoked the plague at its climax.</p>",
        "15": "<p>The Midianite woman: <span class='term'>Kozbi bat-Tsur</span> (כָּזְבִּי בַת-צוּר) — Cozbi daughter of Zur. <em>Kozbi</em> from <em>kazav</em> = to lie, deceive; Cozbi = 'my lie' or 'deceiver.' The woman whose name means deception is the vector of the Baal Peor apostasy. Zur is a Midianite leader — her status makes the public act more provocative: this is not a casual encounter but an alliance-through-marriage attempt.</p>",
        "16": "<p>YHWH's speech to Moses: <span class='term'>tsaror ˀet-hamMidyanim</span> (צָרוֹר אֶת-הַמִּדְיָנִים) — 'treat the Midianites as enemies.' The root <em>tsarar</em> = to bind, constrain, distress; the niphal means 'enemy' (the one who constrains you). The Midianites used a religious and sexual strategy (through Balaam's counsel, see 31:16) where a military strategy would have failed. Their treachery through enticement rather than war is the model of spiritual deception throughout Scripture.</p>",
        "17": "<p><span class='term'>nakeh ˀot-haMidyanim</span> (נַכֵּה אֶת-הַמִּדְיָנִים) — 'strike the Midianites.' The command comes immediately after the theological explanation: because they acted deceptively (<em>niklˀu lakem</em>). The judgment is proportionate to the method: they attacked through intimacy; they will be answered with force. The Midianite war (Num 31) executes this command.</p>",
        "18": "<p><span class='term'>bˀnikhleyhem</span> (בְּנִכְלֵיהֶם, in/through their schemes/treachery) — from <em>nakal</em> = to scheme, act treacherously. The Midianites planned what Balaam could not accomplish through cursing (Num 22-24). The Balaam-Peor connection: Balaam advised Midian to use women as the weapon that curses couldn't provide. The treachery was theological: they used Israel's own sexuality as the mechanism of apostasy.</p>",
    },
    "26": {
        "1": "<p><span class='term'>ˀaḥarey hammagefa</span> (אַחֲרֵי הַמַּגֵּפָה, after the plague) — the second census is triggered by the plague's end. One generation has been counted (Num 1); a plague has killed the last survivors; now the next generation is counted before entering the land. The census marks the transition: those counted in Num 1 were condemned never to enter; those counted here are the ones who will. The arithmetic of judgment has been completed.</p>",
        "2": "<p><span class='term'>seˀu ˀet-roˀsh kol-ˁadat</span> (שְׂאוּ אֶת-רֹאשׁ כָּל-עֲדַת) — 'lift the head of all the congregation.' The <em>nasaˀ roˀsh</em> formula for census-taking (also in Num 1:2) = to count, literally 'to lift the head' of each person. The census recognizes each individual as significant enough to be counted; the <em>roˀsh</em> (head) is lifted — honored, acknowledged, registered.</p>",
        "3": "<p><span class='term'>ˁarvot Moˀav ˁal-Yarden Yˀricho</span> (עַרְבֹת מוֹאָב עַל-יַרְדֵּן יְרִיחוֹ) — plains of Moab beside the Jordan opposite Jericho. This is Israel's final campsite for the rest of Numbers, Deuteronomy, and the threshold of Joshua. Jericho visible across the Jordan is the horizon of promise. Every significant event from here to Joshua 1 happens in this geographic frame — the edge of the land.</p>",
        "4": "<p><span class='term'>kaˀasher ṣivvah YHWH ˀet-Mosheh</span> — as the LORD commanded Moses. The census repeats the command structure of Num 1. YHWH commands → Moses obeys → the people are numbered. The command drives the narrative, not military need or administrative convenience. The census is an act of obedience, not just organization.</p>",
        "5": "<p>Reuben's clans: <span class='term'>Hˀnochi, haPalluˀi, haHetsroni, haKarmi</span>. <em>Reuven</em> (Reuben) = 'see, a son' (Gen 29:32, Leah's cry at his birth). The firstborn tribe lists its clans in the order of their progenitors. Despite Reuben's loss of the firstborn blessing (Gen 49:3-4), the tribe is counted first — genealogical priority survives moral failure in God's census.</p>",
        "6": "<p>Reuben's sub-clans continued. The clan system (mishpaḥot) is the social unit between tribe and individual: typically a group of related families sharing a common ancestor and holding land together. The clan names preserve the memory of the ancestors three or four generations removed from Jacob.</p>",
        "7": "<p>Reuben total: 43,730 — down from 46,500 in the first census (Num 1:21). The reduction of 2,770 men represents the toll of forty years of wilderness mortality and divine judgment on this tribe. Every tribal reduction is a theological accounting.</p>",
        "8": "<p>The son of Pallu: Eliab. The genealogical notation here serves as a transition to the Dathan-Abiram narrative embedded in the census. The census is not merely a counting of living men; it includes the theological history of the families being counted.</p>",
        "9": "<p>The sons of Eliab: Nemuel, Dathan, and Abiram — the Dathan and Abiram who 'were prominent in the congregation' (<span class='term'>qˀrˀy haˁedah</span>). <em>Qˀruˀey</em> = those summoned/called — the chosen leaders who used their prominence to rebel against Moses and Aaron. The census interpolates the rebellion of Num 16 to explain why the Reubenite line of Eliab records no descendants from Dathan and Abiram.</p>",
        "10": "<p>The earth swallowed them and Korah when fire devoured the two hundred and fifty. <span class='term'>wayihyu lˀnes</span> (וַיִּהְיוּ לְנֵס, they became a sign/warning) — a lasting sign. <em>Nes</em> = sign, banner, pole (the same word as the Nehushtan pole in Num 21:8). The catastrophic judgment becomes a permanent visual warning embedded in tribal genealogy — their absence from the clan list is itself the testimony.</p>",
        "11": "<p><span class='term'>ubney Qoraḥ loˀ metu</span> (וּבְנֵי-קֹרַח לֹא-מֵתוּ) — 'but the sons of Korah did not die.' The remarkable parenthetical. Korah was swallowed; his followers were consumed; his sons survived. The Psalms superscriptions (Pss 42-49, 84-85, 87-88) are attributed to the sons of Korah — Israel's greatest choirmasters came from the family of the rebellion's leader. God's judgment is precise; his preservation of the innocent in the midst of judgment is equally precise.</p>",
        "12": "<p>Simeon's clans: Nemuel, Jamin, Jachin, Zerah, Shaul. <em>Shimˁon</em> (Simeon) = 'YHWH has heard' (Gen 29:33). Five clans. In the first census Simeon numbered 59,300 (Num 1:23); the second census (v.14) will record 22,200 — a reduction of 37,100, the largest tribal loss. The Baal Peor catastrophe was primarily a Simeonite disaster (the offending leader was Zimri, a Simeonite chief, 25:14).</p>",
        "13": "<p>Simeon's sub-clans continued: Zerah and Shaul. <em>Zeraḥ</em> (Zerah) = 'rising/dawn' — the same name appears in Judah's genealogy (Gen 38:30; Num 26:20). The coincidence of clan names across tribes reflects the common ancestral pool from which Israel's tribal system is drawn.</p>",
        "14": "<p>Simeon total: 22,200 — down 63% from 59,300. This is the most dramatic tribal decline in the census. The tribe's prominence in the Baal Peor apostasy is the theological explanation. Jacob's prophecy (Gen 49:5-7) foretold that Simeon and Levi would be scattered in Israel; the census shows it beginning with Simeon's collapse.</p>",
        "15": "<p>Gad's clans: Zephon, Haggi, Shuni, Ozni, Eri, Arod, Areli. <em>Gad</em> = 'fortune/good fortune' (Gen 30:11). Seven clan names — suggesting a fuller preservation of Gad's sons in the census. Gad will eventually settle east of the Jordan (Num 32), outside the main land boundaries.</p>",
        "16": "<p>Gad's sub-clans: Ozni (from Ezbon in Gen 46:16) and Eri. The variation between Gen 46's birth list and the Num 26 census list reflects the generational distance — the census counts the clans (mishpaḥot) descended from the sons, not the sons themselves by this point.</p>",
        "17": "<p>Gad's sub-clans continued: Arod and Areli. The seven-clan structure of Gad (compared to Simeon's five) suggests proportionally more clan survival through the wilderness generation. The clan count is not merely organizational — it reflects the relative vitality of each tribal family.</p>",
        "18": "<p>Gad total: 40,500 — down from 45,650 (first census). The tribal arithmetic of loss: 5,150 men fewer. Each number encodes forty years of mortality and divine judgment. The census is simultaneously a counting of the living and an implicit memorial for the dead.</p>",
        "19": "<p>Judah's sons: Er and Onan — but <span class='term'>wayyamot Er waˀOnan bˀˀerets Kˀnaˁan</span> (they died in Canaan). The census embeds the narrative of Gen 38:7-10: Er was wicked; Onan violated the levirate obligation. Their pre-exodus deaths remove two Judahite lines from the census. Judah's tribal continuity runs through Shelah, Pharez (Perez), and Zerah.</p>",
        "20": "<p>Judah's surviving clans: Shelanites, Pharzites (Perezites), Zerahites. <em>Pharez/Perez</em> (פֶּרֶץ) = 'breakthrough' — named at his birth when he pushed ahead of his twin (Gen 38:29). The Pharzite line is the messianic line: Perez → Hezron → Ram → Amminadab → Nahshon → Salmon → Boaz → Obed → Jesse → David → ... → Jesus (Matt 1:3-16; Luke 3:31-33). The census name Pharzites quietly encodes the entire Davidic line.</p>",
        "21": "<p>The Pharzites sub-divided: Hezron (Hezronites) and Hamul (Hamulites). Hezron appears in the genealogy of Ruth and Matthew: Gen 46:12; Ruth 4:18; Matt 1:3. The census subdivision of the messianic line into its next generation is a quiet genealogical thread that will lead eventually to Bethlehem.</p>",
        "22": "<p>Judah total: 76,500 — up from 74,600 (first census). The increase of 1,900 is notable: while most tribes declined, Judah grew. Jacob's blessing (Gen 49:8-12) promised Judah's preeminence; the census documents the beginning of its demographic fulfillment. The royal tribe strengthens as the covenant people move toward the land where their king will rise.</p>",
        "23": "<p>Issachar's clans: Tola, Puvah, Jashub, Shimron. <em>Yissachar</em> (Issachar) = possibly 'man of wages' or 'he will bring wages' (Gen 30:18). Four clans. Issachar's blessing from Jacob emphasizes strength and labor (Gen 49:14-15); the tribe settled in the fertile Jezreel Valley.</p>",
        "24": "<p>Issachar sub-clans: Puvah/Pua (Punites) and Jashub (Jashubites). The name Jashub = 'he returns' — from the root <em>shuv</em>, the repentance vocabulary. The clan's name carries the language of return and turning that will become the central vocabulary of the prophets' call to restoration.</p>",
        "25": "<p>Issachar total: 64,300 — up from 54,400 (first census), an increase of 9,900. The largest proportional increase among the tribes at this point. Issachar's growth during the wilderness period is unexplained by the narrative but documented by the census. YHWH's sovereignty over tribal demographics is not a function of moral performance alone.</p>",
        "26": "<p>Zebulun's clans: Sered, Elon, Jahleel. <em>Zevulun</em> (Zebulun) = 'dwelling' or 'honor' (Gen 30:20). Three clans. Zebulun's territory will border the Sea of Galilee — the region of Jesus' primary ministry (Isa 9:1; Matt 4:13-16). The census preserves Zebulun's three founding clans for the tribe that will host the Light of the World.</p>",
        "27": "<p>Zebulun total: 60,500 — down from 57,400 (first census); actually an increase of 3,100. The text in most MSS gives 60,500. Zebulun's modest growth mirrors the overall pattern: the covenant community survives the wilderness with demographic continuity despite the forty-year mortality sentence.</p>",
        "28": "<p>Joseph's sons: Manasseh and Ephraim. Joseph counted as two tribes (Gen 48:5 — Jacob adopted Joseph's sons as his own). The double portion of Joseph is embedded in the tribal structure: where the other tribes have one entry, Joseph has two. This is the double portion of the firstborn — transferred from Reuben to Joseph (1 Chr 5:1-2) because of Reuben's moral failure.</p>",
        "29": "<p>Manasseh's clans: <span class='term'>liMˀkir yˀlad ˀet-Gilˁad</span> (לְמָכִיר יֻלַּד אֶת-גִּלְעָד) — Machir fathered Gilead. The genealogical embedding: Manasseh → Machir → Gilead → sub-clans. <em>Gilaˁd</em> (Gilead) = 'heap of witness/testimony' — the territory east of the Jordan where part of Manasseh will settle (Num 32). The genealogy maps directly onto the territorial claim.</p>",
        "30": "<p>Gilead's sub-clans: Iezer (Abiezer), Helek, Asriel, Shechem, Shemida, Hepher. The density of sub-clan names here reflects Manasseh's large population and land-claims. Abiezer will appear again in Judges 6:11 as Gideon's clan; Shechem is the city at the center of the land.</p>",
        "31": "<p>Gilead's sub-clans continued: Asriel, Shechem, Shemida. Shechem (שְׁכֶם) = 'shoulder/ridge' — both a place name and a clan name. The toponym and the tribal ancestor share their name, showing the deep connection between Manasseh's genealogy and the geography of central Canaan that the tribe will inherit.</p>",
        "32": "<p>Hepher is named; Zelophehad son of Hepher had no sons, only daughters — <span class='term'>Tselopeḥad ben-Ḥefer lˀ-hayu lo banim ki ˀim-banot</span>. The census pauses to register an inheritance anomaly that was adjudicated in Num 27 and Num 36. The daughters of Zelophehad are named in the middle of the census because their right to inherit land is structurally embedded in the tribal count.</p>",
        "33": "<p>Zelophehad's daughters named: Mahlah, Noah, Hoglah, Milcah, Tirzah. Five daughters who will inherit as a clan in their own right (Num 27:1-11). Tirzah (<em>tirtseh</em>) = 'she is my delight' — also the name of a beautiful city in the northern kingdom (Cant 6:4). The daughters whose legal case established women's inheritance rights are remembered by name in the census.</p>",
        "34": "<p>Manasseh total: 52,700 — down from 32,200 (first census). Actually up — 32,200 to 52,700 is a dramatic increase of 20,500, the largest absolute increase of any tribe. Manasseh nearly doubled during the wilderness period. The double-portion tribe grows disproportionately, as though YHWH's blessing on Joseph's line is accelerating through the wilderness generation.</p>",
        "35": "<p>Ephraim's clans: Shuthelah, Becher, Tahan. <em>Ephrayim</em> (Ephraim) = 'fruitful' (Gen 41:52 — Joseph named him 'for God has made me fruitful'). Jacob elevated Ephraim above Manasseh (Gen 48:19-20) and the census reflects this: Ephraim's clans are listed with the Eranites as a major sub-clan.</p>",
        "36": "<p>Shuthelah's son Eran (Eranites). The layered genealogy: Ephraim → Shuthelah → Eran → Eranites. The depth of the genealogical record through three generations shows which family lines have been most productive and best preserved through the wilderness period.</p>",
        "37": "<p>Ephraim total: 32,500 — down from 40,500 (first census). A decline of 8,000 despite Jacob's blessing of Ephraim above Manasseh. The younger/greater tribe declined while the older/lesser tribe (Manasseh) grew dramatically. The demographics of blessing resist simple theological arithmetic.</p>",
        "38": "<p>Benjamin's clans: Bela, Ashbel, Ahiram, Shupham (Shephupham), Hupham. <em>Binyamin</em> (Benjamin) = 'son of the right hand' (or 'son of the south'). Five founding clans. Benjamin is the youngest and smallest of the original tribes — the last son of Jacob and Rachel.</p>",
        "39": "<p>Benjamin's sub-clans: Ard and Naaman (sons of Bela). The sub-clan structure of Benjamin will become important for the tribe's survival after the near-extermination in Judges 20-21. The detailed genealogical record ensures that even a nearly destroyed tribe can reconstitute itself from its surviving clan structure.</p>",
        "40": "<p>Benjamin's clans continued: Ard (Ardites) and Naaman (Naamites). Benjamin will produce Saul (Israel's first king) and Paul (apostle to the Gentiles). The census of the tribe that will generate these figures records their founding ancestors without any editorial comment on their future significance.</p>",
        "41": "<p>Benjamin total: 45,600 — down from 35,400 (first census); actually up 10,200. The significant increase is notable given Benjamin's later near-destruction in the civil war of Judges 20. The census records a moment of tribal growth that the subsequent narrative will threaten to extinguish.</p>",
        "42": "<p>Dan's clan: Shuham only. <em>Dan</em> = 'he judged' (Gen 30:6). Dan is remarkable for having only a single primary clan — the Shuhamites — with no sub-clans listed. The tribe's genealogical simplicity contrasts with its large population (v.43).</p>",
        "43": "<p>Dan total: 64,400 — down from 62,700 (first census); actually up 1,700. With a single clan, Dan is the most genealogically concentrated major tribe. Its large population from one founding line suggests either exceptional reproductive success or a clan-consolidation over the wilderness period.</p>",
        "44": "<p>Asher's clans: Imnah, Ishvi, Beriah. <em>Asher</em> = 'happy/blessed' (Gen 30:13 — Leah named him this). Three primary clans, with Beriah sub-divided. Asher's blessing from Moses (Deut 33:24) promises: 'Blessed above sons is Asher; let him be the favorite of his brothers, and let him dip his foot in oil' — the fertile coastal territory.</p>",
        "45": "<p>Beriah's sons: Heber and Malchiel. The sub-clan structure of Beriah (Heber → Heberites; Malchiel → Malchielites) preserves two more generations of Asherite genealogy. Heber the Kenite (Judges 4:11) and his wife Jael (who killed Sisera) — while a different family entirely — show that the name Heber appears in the tribal periphery as well.</p>",
        "46": "<p>Asher's daughter: <span class='term'>Sheraḥ</span> (שֶׂרַח). The female name appears in the census as a named exception — a daughter of Asher recorded by name. This is one of the few named women in the census lists. The reason for the exception is unclear: later tradition credits Serah with extraordinary longevity, surviving from the exodus generation to the time of David.</p>",
        "47": "<p>Asher total: 53,400 — down from 41,500 (first census); actually up 11,900. A significant increase for a tribe in the coastal region. Asher's growth mirrors the coastal fertility that Moses' blessing anticipates.</p>",
        "48": "<p>Naphtali's clans: Jahzeel, Guni, Jezer, Shillem. <em>Naphtali</em> = 'my wrestling' (Gen 30:8 — Rachel's wrestling with Leah). Four clans. Naphtali's territory will include the western shore of the Sea of Galilee — the setting of much of Jesus' Galilean ministry (Matt 4:13-16 cites Isa 9:1's Naphtali/Zebulun as the region of the Messiah's light).</p>",
        "49": "<p>Naphtali's sub-clans: Jahzeelites, Gunites, Jezerites, Shillemites. The four-clan structure gives Naphtali a modest but stable genealogical base. Naphtali declined from 53,400 to 45,400 (8,000 fewer) — one of the larger tribal decreases in the second census.</p>",
        "50": "<p>Naphtali total: 45,400 — down from 53,400 (first census), a loss of 8,000. The decline of the tribe whose land will host the majority of Jesus' public ministry is narrated without theological comment. The census records facts; the theological significance emerges across centuries of subsequent history.</p>",
        "51": "<p><span class='term'>ˀeleh pˀquday bney Yisraˀel</span> — the grand total: <span class='term'>sheish-meˀot ˀelep weˀeḥad ˀalaphim ushˀvah meˀot ushloˀshim</span> — 601,730. Slightly less than the 603,550 of the first census (Num 1:46). The forty years of plague and judgment have taken a net toll of 1,820 men of military age. The covenant community survived the wilderness — diminished but intact.</p>",
        "52": "<p>YHWH speaks about the land distribution. The second census is not merely administrative; it is the basis for territorial allocation. Every man counted in the census represents a land claim for his household. The census connects counting to inheritance — being numbered is the precondition of receiving the land.</p>",
        "53": "<p><span class='term'>lˀˀelleh teḥalek haˀarets bˀnaḥalah</span> (לָאֵלֶּה תֵּחָלֵק הָאָרֶץ בְּנַחֲלָה) — to these the land shall be divided as <em>naḥalah</em> (inheritance). The census-to-land connection is explicit. <em>Naḥalah</em> = ancestral inheritance, the land permanently assigned to a family group. The NT applies this language to the heavenly inheritance (1 Pet 1:4; Eph 1:11).</p>",
        "54": "<p><span class='term'>larav tarbeh naḥalato wˀlammˁat tamˁit naḥalato</span> — larger tribes receive larger portions, smaller tribes smaller ones. The proportionality principle: the land inheritance is sized to the family that will work it. The principle connects demographic vitality to territorial provision — larger covenant communities require larger land-grants. The heavenly inheritance, by contrast, is equally large for all (John 14:2).</p>",
        "55": "<p><span class='term'>ˀakh bˀgoral yeḥalek ˀet-haˀarets</span> (אַךְ בְּגוֹרָל יֵחָלֵק אֶת-הָאָרֶץ) — 'yet by lot the land shall be divided.' The <em>goral</em> (lot) system introduces divine sovereignty into the distribution: size determines approximate allocation but the specific location within each size-class is determined by lot. The lot is the mechanism of YHWH's sovereign will (Prov 16:33: 'the lot is cast into the lap, but its every decision is from the LORD').</p>",
        "56": "<p>Distribution by lot applies to both large and small tribes: the lot determines location, the census determines size. The two-variable system prevents both favoritism (by location) and inequality (by population size). The combination of divine sovereignty (lot) and demographic justice (proportional size) models a governance principle where God's will and human realities are both honored.</p>",
        "57": "<p>The Levites are listed separately. Their clans: Gershon, Kohath, Merari — the same three that organized the transport of the tabernacle (Num 3-4). <em>Levi</em> = 'attached/joined' (Gen 29:34). The Levites' distinct listing outside the main tribal census foreshadows their distinct role: no land inheritance, but cities and tithes throughout all the other tribes' lands.</p>",
        "58": "<p>Other Levitical families: Libnites, Hebronites, Mahlites, Mushites, Korahites. The Korah here is the Levitical ancestor (not the rebel of Num 16); the families are distinct. The Mushites are the descendants of Moses' father's family (Mushi from Moses' father Amram's line). The Levitical genealogy preserves both the priestly line and its extended family structure.</p>",
        "59": "<p><span class='term'>shem ˀeshet ˁAmram Yokheved bat-Levi</span> — Amram's wife Jochebed, daughter of Levi, born to Levi in Egypt. Jochebed is the only person in the Torah described as <em>born to Levi</em> — she is the direct daughter of the patriarch. Her birth is noted in the census because she is the mother of Aaron, Moses, and Miriam — the three leaders of the exodus generation who appear in the same parenthetical as this genealogical note.</p>",
        "60": "<p>Aaron's sons: Nadab, Abihu, Eleazar, Ithamar. The four sons who were ordained in Lev 8-9. Nadab and Abihu offered unauthorized fire (Lev 10:1-2) and died; the priesthood continued through Eleazar and Ithamar, the two survivors whose lines will divide the priestly service throughout Israel's history.</p>",
        "61": "<p><span class='term'>wayyamot Nadav waˀAvihu bˀhaqˀrivam ˀesh zarah</span> (וַיָּמָת נָדָב וַאֲבִיהוּא בְּהַקְרִיבָם אֵשׁ זָרָה) — Nadab and Abihu died when they offered unauthorized fire. The census re-registers their deaths from Lev 10: the priestly genealogy incorporates the record of priestly failure. The two deaths reduced Aaron's line to Eleazar and Ithamar — the ancestors of the entire subsequent Israelite priesthood.</p>",
        "62": "<p>Levi total: 23,000 males one month and older — not counted among the main census because <span class='term'>ki loˀ hitpaqˀdu bˀtok bney Yisraˀel ki loˀ nittan lahem naḥalah</span> (they were not numbered among Israel because no inheritance was given to them). The Levites' exclusion from land-inheritance is their census identity: they are counted separately, for a different purpose, with different rules. Their inheritance is YHWH himself (Num 18:20).</p>",
        "63": "<p>Summary header: Moses and Eleazar the priest registered the Israelites in the plains of Moab by the Jordan. The geographic frame recurs: the Jordan plain opposite Jericho is the setting of the final preparation. Eleazar, not Aaron (who died in ch 20), is now the high priest — the generation of leadership has turned.</p>",
        "64": "<p><span class='term'>ubˀˀeleh loˀ-haya ˀish meˀpˀqudy Mosheh wˀˀAharon</span> (וּבְאֵלֶּה לֹא-הָיָה אִישׁ מִפְּקוּדֵי מֹשֶׁה וְאַהֲרֹן) — 'and not one of these was among those Moses and Aaron registered.' The entire first census cohort is gone. This is the structural verdict: YHWH's judgment was complete. Every man of military age from the Sinai census — 603,550 souls — died in the wilderness. Not one survived except two.</p>",
        "65": "<p><span class='term'>ki-ˀamar YHWH lahem mot yamutu bamidbar</span> (כִּי-אָמַר יְהוָה לָהֶם מוֹת יָמוּתוּ בַּמִּדְבָּר) — 'for YHWH had said of them: They shall surely die in the wilderness.' The divine word pronounced in Num 14:29-35 was executed with complete faithfulness: every man of that generation died. <span class='term'>wˀloˀ-notar ˀish mehem ki ˀim-Kalev... wiYˀhoshuˁa</span> — 'not one of them remained except Caleb... and Joshua.' Two survivors from 603,550. The ratio of faithfulness to the entire first generation: two in over six hundred thousand. Caleb and Joshua are the remnant theology in miniature — the few who cling to the promise through the dying generation.</p>",
    },
}


def main():
    data = load_comm("mkt-original", "numbers")
    merge_comm(data, NUMBERS)
    save_comm("mkt-original", "numbers", data)


if __name__ == "__main__":
    main()
